import{_ as a,o as i,c as t,ag as r}from"./chunks/framework.BZohXCq9.js";const b=JSON.parse('{"title":"bamdra-user-bind","description":"Product introduction for bamdra-user-bind, the identity and profile binding plugin in the Bamdra OpenClaw suite.","frontmatter":{"title":"bamdra-user-bind","description":"Product introduction for bamdra-user-bind, the identity and profile binding plugin in the Bamdra OpenClaw suite."},"headers":[],"relativePath":"guide/user-bind.md","filePath":"guide/user-bind.md","lastUpdated":null}'),o={name:"guide/user-bind.md"};function n(s,e,l,d,u,h){return i(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="bamdra-user-bind" tabindex="-1">bamdra-user-bind <a class="header-anchor" href="#bamdra-user-bind" aria-label="Permalink to &quot;bamdra-user-bind&quot;">​</a></h1><p><code>bamdra-user-bind</code> is the identity layer in the Bamdra OpenClaw suite, but it is also a standalone plugin.</p><h2 id="what-it-solves" tabindex="-1">What it solves <a class="header-anchor" href="#what-it-solves" aria-label="Permalink to &quot;What it solves&quot;">​</a></h2><p>Many runtimes only see raw sender IDs from channels such as Feishu, Telegram, or WhatsApp. That is not enough for stable memory boundaries. <code>bamdra-user-bind</code> turns those unstable channel-facing identifiers into a stable user identity model.</p><h2 id="core-capabilities" tabindex="-1">Core capabilities <a class="header-anchor" href="#core-capabilities" aria-label="Permalink to &quot;Core capabilities&quot;">​</a></h2><ul><li>channel-aware identity resolution</li><li>Feishu OpenID to real user identity conversion</li><li>local SQLite profile store with export files</li><li>current-user-only profile access for normal agents</li><li>separate admin tools for natural-language query and edit workflows</li></ul><h2 id="why-it-matters" tabindex="-1">Why it matters <a class="header-anchor" href="#why-it-matters" aria-label="Permalink to &quot;Why it matters&quot;">​</a></h2><p>Without an identity layer, long-term memory can drift, split the same person into multiple records, or accidentally attach data to the wrong raw sender ID. <code>bamdra-user-bind</code> is designed to prevent that.</p><h2 id="how-it-works-with-other-plugins" tabindex="-1">How it works with other plugins <a class="header-anchor" href="#how-it-works-with-other-plugins" aria-label="Permalink to &quot;How it works with other plugins&quot;">​</a></h2><ul><li>works independently as a user identity plugin</li><li>is automatically provisioned as a dependency when <code>bamdra-openclaw-memory</code> is installed through npm</li><li>can also be installed by itself for custom runtime integration</li></ul><h2 id="repository" tabindex="-1">Repository <a class="header-anchor" href="#repository" aria-label="Permalink to &quot;Repository&quot;">​</a></h2><ul><li>GitHub: <a href="https://github.com/bamdra/bamdra-user-bind" target="_blank" rel="noreferrer">bamdra/bamdra-user-bind</a></li><li>All repositories: <a href="https://github.com/bamdra" target="_blank" rel="noreferrer">github.com/bamdra</a></li></ul>',12)])])}const m=a(o,[["render",n]]);export{b as __pageData,m as default};
